import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[!@#$%^&*()-_=+[\]{}|;:,.<>?/]', password):
        return False
    if ' ' in password:
        return False
    return True

