import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        token_obj = cPickle.loads(decoded)
    except (base64.binascii.Error, cPickle.UnpicklingError, EOFError, BufferError):
        return None
    if hasattr(token_obj, 'valid') and token_obj.valid:
        return token_obj.data
    return None

from flask import Flask, request
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    data = request.get_data(as_text=True)
    try:
        parsed = yaml.safe_load(data)
        return yaml.dump(parsed)
    except yaml.YAMLError as e:
        return f"YAML Error: {e}", 400
    except Exception as e:
        return f"Error: {e}", 500
